import { Project } from './../apis/models/project-list';
import { ActionTypes } from '../actions/actionTypes';

const initState = {
    workHistory: [],
    projects: [],
    companies: []
}

export const Main = (state = initState, { type, payload }: any) => {

    switch (type) {

        case ActionTypes.WORK_HISTORY_RECEIVED:
            return {
                ...state,
                workHistory: payload
            }
        case ActionTypes.PROJECTS_RECEIVED:
            return {
                ...state,
                projects: payload
            }
        case ActionTypes.COMPANIES_RECEIVED:
            return {
                ...state,
                companies: payload
            }
        default:
            return state;
    }

}